problem:
If each of the variables represents a different digit, what is the value of $a+b+c+d$?

[asy]
label("$a$",(1,0),E);
label("$b$",(2,0),E);
label("$c$",(3,0),E);
label("$d$",(1,-1),E);
label("$c$",(2,-1),E);
label("$a$",(3,-1),E);
label("+",(-2,-1),E);
draw((-2.1,-1.4)--(4.1,-1.4),linewidth(0.5));
label("1",(0,-2),E);
for (int i =0; i<3; ++i) {
label("0",(1+i,-2),E);
}
[/asy]

